#include &lt;string.h&gt;
#include &lt;arpa/inet.h&gt;

#define PORT 8080
#define MAX_PAYLOAD 1024

int main() {
    // 1. Create a DGRAM socket (UDP)
    int sockfd = socket(AF_INET, SOCK_DGRAM, 0);

    struct sockaddr_in server_addr = {0};
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    // 2. Bind. Notice there is NO listen() and NO accept().
    if (bind(sockfd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("Bind failed");
        return 1;
    }

    printf("UDP Receiver active on port %d.\n", PORT);

    char buffer[MAX_PAYLOAD];
    struct sockaddr_in client_addr;
    socklen_t client_len = sizeof(client_addr);

    while (1) {
        // 3. recvfrom blocks until ANY datagram arrives.
        // It populates client_addr so we know precisely who sent it.
        ssize_t bytes = recvfrom(sockfd, buffer, MAX_PAYLOAD, 0, 
                                 (struct sockaddr *)&client_addr, &client_len);

        if (bytes > 0) {
            buffer[bytes] = '\0'; // Null-terminate for printing
            printf("Received %zd bytes from %s\n", bytes, inet_ntoa(client_addr.sin_addr));

            // 4. Instantly reply using sendto()
            char *reply = "ACK";
            sendto(sockfd, reply, strlen(reply), 0, 
                   (struct sockaddr *)&client_addr, client_len);
        }
    }
    return 0;
}

