#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;
#include &lt;string.h&gt;
#include &lt;arpa/inet.h&gt;
#include &lt;sys/socket.h&gt;

// The core Game State we need to transmit
typedef struct {
    uint8_t player_id;
    uint32_t health;
    uint32_t pos_x;
    uint32_t pos_y;
} GameState;

// 1. Serialization (Sender Side)
// We construct a pure byte array, mathematically forcing the data into 
// Big-Endian Network Byte Order (htonl), completely immune to compiler padding.
size_t serialize_gamestate(const GameState *state, uint8_t *buffer) {
    size_t offset = 0;

    buffer[offset++] = state->player_id; // 1 Byte

    uint32_t net_health = htonl(state->health);
    memcpy(buffer + offset, &net_health, 4);
    offset += 4;

    uint32_t net_x = htonl(state->pos_x);
    memcpy(buffer + offset, &net_x, 4);
    offset += 4;

    uint32_t net_y = htonl(state->pos_y);
    memcpy(buffer + offset, &net_y, 4);
    offset += 4;

    return offset; // Exact bytes used (13 bytes)
}

// 2. Deserialization (Receiver Side)
// Reconstructs the struct from the raw Big-Endian payload
void deserialize_gamestate(const uint8_t *buffer, GameState *state) {
    size_t offset = 0;

    state->player_id = buffer[offset++];

    uint32_t net_health;
    memcpy(&net_health, buffer + offset, 4);
    state->health = ntohl(net_health); // Convert Network back to Host order
    offset += 4;

    uint32_t net_x;
    memcpy(&net_x, buffer + offset, 4);
    state->pos_x = ntohl(net_x);
    offset += 4;

    uint32_t net_y;
    memcpy(&net_y, buffer + offset, 4);
    state->pos_y = ntohl(net_y);
}
